queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?role_title WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:staff_role_id ?cg . ?child a :Staff_Roles ; p:role_id ?cg . ?l p:retail_store_id ?pg . ?parent a :Retail_Stores ; p:store_id ?pg . } GROUP BY ?child }
  ?child p:role_title ?role_title .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Retail_Stores } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?role_title WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:staff_role_id ?cg . ?child a :Staff_Roles ; p:role_id ?cg . ?l p:retail_store_id ?pg . ?parent a :Retail_Stores ; p:store_id ?pg . } GROUP BY ?child }
  ?child p:role_title ?role_title .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Retail_Stores } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?store_name ?role_title WHERE {
  ?retail_stores_staff_roles a :Retail_Stores_Staff_Roles .
  ?staff_roles a :Staff_Roles .
  ?retail_stores_staff_roles p:hasStaff_Roles ?staff_roles .
  ?retail_stores a :Retail_Stores .
  ?retail_stores_staff_roles p:hasRetail_Stores ?retail_stores .
  ?retail_stores p:store_name ?store_name .
  ?staff_roles p:role_title ?role_title .
} }
}
